     1→import { useState } from "react";
     2→import { AppLayout } from "@/components/layout";
     3→import { useListSources, useCreateSource, useUpdateSource, useDeleteSource, useScrapeSource, useScrapeAll } from "@workspace/api-client-react";
     4→import type { SourceWithUrls, CreateSourceRequest, UpdateSourceRequest } from "@workspace/api-client-react/src/generated/api.schemas";
     5→import { Card, CardContent } from "@/components/ui/card";
     6→import { Button } from "@/components/ui/button";
     7→import { Input } from "@/components/ui/input";
     8→import { Label } from "@/components/ui/label";
     9→import { Badge } from "@/components/ui/badge";
    10→import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
    11→import { Switch } from "@/components/ui/switch";
    12→import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
    13→import { Plus, Search, RefreshCw, Pencil, Trash2, Globe, ChevronDown, ChevronRight, AlertTriangle, Link as LinkIcon } from "lucide-react";
    14→import { useToast } from "@/components/ui/use-toast";
    15→import { useQueryClient } from "@tanstack/react-query";
    16→import { format } from "date-fns";
    17→import { it } from "date-fns/locale";
    18→
    19→export default function Fonti() {
    20→  const { data: sources, isLoading } = useListSources();
    21→  const { toast } = useToast();
    22→  const queryClient = useQueryClient();
    23→  const scrapeAllMutation = useScrapeAll();
    24→  
    25→  const [searchTerm, setSearchTerm] = useState("");
    26→  const [expandedRows, setExpandedRows] = useState<Record<number, boolean>>({});
    27→  
    28→  // Modals state
    29→  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
    30→  const [editingSource, setEditingSource] = useState<SourceWithUrls | null>(null);
    31→
    32→  const toggleRow = (id: number) => {
    33→    setExpandedRows(prev => ({ ...prev, [id]: !prev[id] }));
    34→  };
    35→
    36→  const handleScrapeAll = async () => {
    37→    try {
    38→      await scrapeAllMutation.mutateAsync();
    39→      toast({ title: "Scraping avviato", description: "Richiesta inviata a tutte le fonti." });
    40→    } catch (e) {
    41→      toast({ title: "Errore", variant: "destructive", description: "Impossibile avviare lo scraping globale." });
    42→    }
    43→  };
    44→
    45→  const filteredSources = sources?.filter(s => 
    46→    s.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    47→    s.urls.some(u => u.url.toLowerCase().includes(searchTerm.toLowerCase()))
    48→  ) || [];
    49→
    50→  return (
    51→    <AppLayout>
    52→      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mb-8">
    53→        <div>
    54→          <h1 className="text-3xl font-bold font-display text-foreground tracking-tight">Fonti</h1>
    55→          <p className="text-muted-foreground mt-1">Gestisci i siti web e gli URL da cui estrarre gli eventi.</p>
    56→        </div>
    57→        <div className="flex gap-3">
    58→          <Button variant="outline" onClick={handleScrapeAll} disabled={scrapeAllMutation.isPending} className="bg-background">
    59→            <RefreshCw className={`w-4 h-4 mr-2 ${scrapeAllMutation.isPending ? 'animate-spin' : ''}`} />
    60→            Scrapa Tutte
    61→          </Button>
    62→          <Button onClick={() => { setEditingSource(null); setIsEditModalOpen(true); }} className="shadow-md">
    63→            <Plus className="w-4 h-4 mr-2" />
    64→            Aggiungi Fonte
    65→          </Button>
    66→        </div>
    67→      </div>
    68→
    69→      <div className="mb-6 flex relative">
    70→        <Search className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
    71→        <Input 
    72→          placeholder="Cerca per nome o URL..." 
    73→          className="pl-10 max-w-md bg-background"
    74→          value={searchTerm}
    75→          onChange={(e) => setSearchTerm(e.target.value)}
    76→        />
    77→      </div>
    78→
    79→      {isLoading ? (
    80→        <div className="space-y-4">
    81→          {[1, 2, 3].map(i => <div key={i} className="h-16 bg-muted animate-pulse rounded-xl"></div>)}
    82→        </div>
    83→      ) : filteredSources.length === 0 ? (
    84→        <Card className="border-dashed">
    85→          <CardContent className="flex flex-col items-center justify-center py-12 text-center">
    86→            <Globe className="w-12 h-12 text-muted-foreground/50 mb-4" />
    87→            <h3 className="text-lg font-medium text-foreground">Nessuna fonte trovata</h3>
    88→            <p className="text-muted-foreground text-sm max-w-sm mt-1 mb-4">Aggiungi la tua prima fonte per iniziare ad estrarre eventi automaticamente.</p>
    89→            <Button onClick={() => { setEditingSource(null); setIsEditModalOpen(true); }}>Aggiungi Fonte</Button>
    90→          </CardContent>
    91→        </Card>
    92→      ) : (
    93→        <div className="bg-card rounded-xl shadow-sm border border-border/50 overflow-hidden">
    94→          <div className="grid grid-cols-[auto_1fr_auto_auto_auto] gap-4 p-4 bg-muted/30 border-b border-border/50 text-sm font-medium text-muted-foreground">
    95→            <div className="w-8"></div>
    96→            <div>Nome</div>
    97→            <div className="w-32 hidden sm:block">Scraper</div>
    98→            <div className="w-48 hidden md:block">Ultimo Scrape</div>
    99→            <div className="w-24 text-right">Stato</div>
   100→          </div>
   101→          
   102→          <div className="divide-y divide-border/30">
   103→            {filteredSources.map((source) => (
   104→              <SourceRow 
   105→                key={source.id} 
   106→                source={source} 
   107→                isExpanded={!!expandedRows[source.id]} 
   108→                onToggle={() => toggleRow(source.id)} 
   109→                onEdit={() => { setEditingSource(source); setIsEditModalOpen(true); }}
   110→              />
   111→            ))}
   112→          </div>
   113→        </div>
   114→      )}
   115→
   116→      {isEditModalOpen && (
   117→        <SourceModal 
   118→          source={editingSource} 
   119→          isOpen={isEditModalOpen} 
   120→          onClose={() => setIsEditModalOpen(false)} 
   121→        />
   122→      )}
   123→    </AppLayout>
   124→  );
   125→}
   126→
   127→function SourceRow({ source, isExpanded, onToggle, onEdit }: { source: SourceWithUrls, isExpanded: boolean, onToggle: () => void, onEdit: () => void }) {
   128→  const scrapeMutation = useScrapeSource();
   129→  const { toast } = useToast();
   130→
   131→  const handleScrape = async (e: React.MouseEvent) => {
   132→    e.stopPropagation();
   133→    try {
   134→      await scrapeMutation.mutateAsync({ id: source.id });
   135→      toast({ title: "Scraping avviato", description: `Avviata estrazione per ${source.name}` });
   136→    } catch (err) {
   137→      toast({ title: "Errore", variant: "destructive", description: "Impossibile avviare lo scraping" });
   138→    }
   139→  };
   140→
   141→  return (
   142→    <div className="group">
   143→      <div 
   144→        className="grid grid-cols-[auto_1fr_auto_auto_auto] gap-4 p-4 items-center hover:bg-muted/10 transition-colors cursor-pointer"
   145→        onClick={onToggle}
   146→      >
   147→        <div className="w-8 flex items-center justify-center text-muted-foreground">
   148→          {isExpanded ? <ChevronDown className="w-5 h-5" /> : <ChevronRight className="w-5 h-5" />}
   149→        </div>
   150→        <div className="min-w-0">
   151→          <div className="font-medium text-foreground truncate flex items-center gap-2">
   152→            {source.name}
   153→            <Badge variant="secondary" className="text-xs bg-muted text-muted-foreground font-normal rounded-full px-2">
   154→              {source.urls.length} URL
   155→            </Badge>
   156→          </div>
   157→          {source.preferredScraper === 'browseract' && !source.browseractWorkflowId && (
   158→            <div className="text-[10px] text-amber-500 mt-1 flex items-center gap-1 font-medium">
   159→              <AlertTriangle className="w-3 h-3" /> Sistema di backup (Nessun ID workflow)
   160→            </div>
   161→          )}
   162→        </div>
   163→        <div className="w-32 hidden sm:flex items-center text-sm">
   164→          {source.preferredScraper === 'browseract' ? (
   165→            <Badge variant="outline" className="text-blue-600 bg-blue-50 border-blue-200">BrowserAct</Badge>
   166→          ) : (
   167→            <Badge variant="outline" className="text-purple-600 bg-purple-50 border-purple-200">Claude</Badge>
   168→          )}
   169→        </div>
   170→        <div className="w-48 hidden md:block text-sm text-muted-foreground">
   171→          {source.lastScrapedAt ? format(new Date(source.lastScrapedAt), 'dd MMM, HH:mm', { locale: it }) : '-'}
   172→        </div>
   173→        <div className="w-24 flex items-center justify-end gap-2">
   174→          {!source.active && <Badge variant="secondary" className="bg-muted">Inattivo</Badge>}
   175→          <Button variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground hover:text-primary" onClick={(e) => { e.stopPropagation(); onEdit(); }}>
   176→            <Pencil className="w-4 h-4" />
   177→          </Button>
   178→        </div>
   179→      </div>
   180→      
   181→      {isExpanded && (
   182→        <div className="bg-muted/10 px-4 py-4 border-t border-border/30 pl-[4rem]">
   183→          <div className="flex justify-between items-center mb-4">
   184→            <h4 className="text-sm font-medium text-foreground">URL configurati</h4>
   185→            <Button size="sm" variant="outline" onClick={handleScrape} disabled={scrapeMutation.isPending}>
   186→              <RefreshCw className={`w-3 h-3 mr-2 ${scrapeMutation.isPending ? 'animate-spin' : ''}`} />
   187→              Scrapa Fonte Ora
   188→            </Button>
   189→          </div>
   190→          <div className="space-y-2">
   191→            {source.urls.map((url) => (
   192→              <div key={url.id} className="flex items-center gap-3 p-3 rounded-lg bg-background border border-border/50 text-sm">
   193→                <LinkIcon className="w-4 h-4 text-muted-foreground shrink-0" />
   194→                <div className="flex-1 min-w-0">
   195→                  {url.label && <div className="font-medium text-xs mb-0.5">{url.label}</div>}
   196→                  <a href={url.url} target="_blank" rel="noopener noreferrer" className="text-primary hover:underline truncate block">
   197→                    {url.url}
   198→                  </a>
   199→                </div>
   200→                {!url.active && <Badge variant="secondary" className="text-[10px]">Inattivo</Badge>}
   201→              </div>
   202→            ))}
   203→          </div>
   204→        </div>
   205→      )}
   206→    </div>
   207→  );
   208→}
