   210→function SourceModal({ source, isOpen, onClose }: { source: SourceWithUrls | null, isOpen: boolean, onClose: () => void }) {
   211→  const createMutation = useCreateSource();
   212→  const updateMutation = useUpdateSource();
   213→  const deleteMutation = useDeleteSource();
   214→  const queryClient = useQueryClient();
   215→  const { toast } = useToast();
   216→
   217→  const [formData, setFormData] = useState({
   218→    name: source?.name || "",
   219→    preferredScraper: source?.preferredScraper || "browseract",
   220→    browseractWorkflowId: source?.browseractWorkflowId || "",
   221→    active: source !== null ? source.active : true,
   222→    urls: source?.urls.map(u => ({ id: u.id, url: u.url, label: u.label || "", active: u.active })) || [{ url: "", label: "", active: true }]
   223→  });
   224→
   225→  const handleSave = async () => {
   226→    if (!formData.name) return toast({ title: "Nome mancante", variant: "destructive" });
   227→    if (!formData.urls[0].url) return toast({ title: "Inserisci almeno un URL", variant: "destructive" });
   228→
   229→    try {
   230→      const payload = {
   231→        name: formData.name,
   232→        preferredScraper: formData.preferredScraper,
   233→        browseractWorkflowId: formData.browseractWorkflowId || null,
   234→        active: formData.active,
   235→        urls: formData.urls.filter(u => u.url.trim() !== "").map(u => ({
   236→          ...(u.id ? { id: u.id } : {}),
   237→          url: u.url,
   238→          label: u.label || null,
   239→          active: u.active
   240→        }))
   241→      };
   242→
   243→      if (source) {
   244→        await updateMutation.mutateAsync({ id: source.id, data: payload as UpdateSourceRequest });
   245→        toast({ title: "Fonte aggiornata" });
   246→      } else {
   247→        await createMutation.mutateAsync({ data: payload as CreateSourceRequest });
   248→        toast({ title: "Fonte creata" });
   249→      }
   250→      queryClient.invalidateQueries({ queryKey: ["/api/sources"] });
   251→      onClose();
   252→    } catch (e) {
   253→      toast({ title: "Errore durante il salvataggio", variant: "destructive" });
   254→    }
   255→  };
   256→
   257→  const handleDelete = async () => {
   258→    if (!source) return;
   259→    if (confirm("Sei sicuro di voler eliminare questa fonte? Tutti gli eventi ad essa collegati rimarranno.")) {
   260→      try {
   261→        await deleteMutation.mutateAsync({ id: source.id });
   262→        toast({ title: "Fonte eliminata" });
   263→        queryClient.invalidateQueries({ queryKey: ["/api/sources"] });
   264→        onClose();
   265→      } catch (e) {
   266→        toast({ title: "Errore", variant: "destructive" });
   267→      }
   268→    }
   269→  };
   270→
   271→  return (
   272→    <Dialog open={isOpen} onOpenChange={onClose}>
   273→      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
   274→        <DialogHeader>
   275→          <DialogTitle>{source ? "Modifica Fonte" : "Aggiungi Fonte"}</DialogTitle>
   276→        </DialogHeader>
   277→        
   278→        <div className="grid gap-6 py-4">
   279→          <div className="grid gap-2">
   280→            <Label>Nome Fonte</Label>
   281→            <Input value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} placeholder="Es. Comune di Varese" />
   282→          </div>
   283→          
   284→          <div className="grid sm:grid-cols-2 gap-4">
   285→            <div className="grid gap-2">
   286→              <Label>Motore preferito</Label>
   287→              <Select value={formData.preferredScraper} onValueChange={(v) => setFormData({...formData, preferredScraper: v})}>
   288→                <SelectTrigger><SelectValue /></SelectTrigger>
   289→                <SelectContent>
   290→                  <SelectItem value="browseract">BrowserAct (Scraping avanzato)</SelectItem>
   291→                  <SelectItem value="claude_fallback">Claude (Scraping base)</SelectItem>
   292→                </SelectContent>
   293→              </Select>
   294→            </div>
   295→            <div className="grid gap-2">
   296→              <Label>BrowserAct Workflow ID (opzionale)</Label>
   297→              <Input value={formData.browseractWorkflowId} onChange={e => setFormData({...formData, browseractWorkflowId: e.target.value})} placeholder="ID del workflow" disabled={formData.preferredScraper === 'claude_fallback'} />
   298→            </div>
   299→          </div>
   300→
   301→          <div className="flex items-center space-x-2">
   302→            <Switch checked={formData.active} onCheckedChange={(c) => setFormData({...formData, active: c})} />
   303→            <Label>Fonte attiva</Label>
   304→          </div>
   305→
   306→          <div className="space-y-4">
   307→            <div className="flex justify-between items-center">
   308→              <Label className="text-base">URLs da scansionare</Label>
   309→              <Button type="button" variant="outline" size="sm" onClick={() => setFormData({...formData, urls: [...formData.urls, { url: "", label: "", active: true }]})}>
   310→                <Plus className="w-3 h-3 mr-2" /> Aggiungi URL
   311→              </Button>
   312→            </div>
   313→            
   314→            <div className="space-y-3">
   315→              {formData.urls.map((url, i) => (
   316→                <div key={i} className="flex gap-2 items-start bg-muted/20 p-3 rounded-lg border border-border">
   317→                  <div className="grid gap-3 flex-1">
   318→                    <Input placeholder="https://..." value={url.url} onChange={e => {
   319→                      const newUrls = [...formData.urls];
   320→                      newUrls[i].url = e.target.value;
   321→                      setFormData({...formData, urls: newUrls});
   322→                    }} />
   323→                    <div className="flex gap-2 items-center">
   324→                      <Input placeholder="Etichetta (es. Pagina eventi)" value={url.label} className="h-8 text-sm" onChange={e => {
   325→                        const newUrls = [...formData.urls];
   326→                        newUrls[i].label = e.target.value;
   327→                        setFormData({...formData, urls: newUrls});
   328→                      }} />
   329→                      <div className="flex items-center gap-2 shrink-0">
   330→                        <Switch checked={url.active} onCheckedChange={(c) => {
   331→                          const newUrls = [...formData.urls];
   332→                          newUrls[i].active = c;
   333→                          setFormData({...formData, urls: newUrls});
   334→                        }} />
   335→                        <span className="text-xs text-muted-foreground w-12">{url.active ? 'Attivo' : 'Spento'}</span>
   336→                      </div>
   337→                    </div>
   338→                  </div>
   339→                  {formData.urls.length > 1 && (
   340→                    <Button variant="ghost" size="icon" className="text-destructive shrink-0" onClick={() => {
   341→                      const newUrls = formData.urls.filter((_, index) => index !== i);
   342→                      setFormData({...formData, urls: newUrls});
   343→                    }}>
   344→                      <Trash2 className="w-4 h-4" />
   345→                    </Button>
   346→                  )}
   347→                </div>
   348→              ))}
   349→            </div>
   350→          </div>
   351→        </div>
   352→
   353→        <DialogFooter className="flex items-center sm:justify-between w-full">
   354→          {source ? (
   355→            <Button variant="destructive" onClick={handleDelete} className="shadow-sm">Elimina</Button>
   356→          ) : <div></div>}
   357→          <div className="flex gap-2">
   358→            <Button variant="outline" onClick={onClose}>Annulla</Button>
   359→            <Button onClick={handleSave} disabled={createMutation.isPending || updateMutation.isPending}>Salva</Button>
   360→          </div>
   361→        </DialogFooter>
   362→      </DialogContent>
   363→    </Dialog>
   364→  );
   365→}
